// Time:  O(n * a * c), n = len(price), a = maxAmount, c = maxCoupons
// Space: O(a * c)

// dp
class Solution {
public:
    int maxTastiness(vector<int>& price, vector<int>& tastiness, int maxAmount, int maxCoupons) {
        vector<vector<int>> dp(maxAmount + 1, vector<int>(maxCoupons + 1));
        for (int k = 0; k < size(price); ++k) {
            for (int i = maxAmount; i - price[k] / 2 >= 0; --i) {
                for (int j = maxCoupons; j >= 0; --j) {
                    if (i - price[k] >= 0) {
                        dp[i][j] = max(dp[i][j], tastiness[k] + dp[i - price[k]][j]);
                    }
                    if (j - 1 >= 0) {
                        dp[i][j] = max(dp[i][j], tastiness[k] + dp[i - price[k] / 2][j - 1]);
                    }
                }
            }
        }
        return dp[maxAmount][maxCoupons];
    }
};

# Time:  O(n * a * c), n = len(price), a = maxAmount, c = maxCoupons
# Space: O(a * c)

import itertools


# dp
class Solution(object):
    def maxTastiness(self, price, tastiness, maxAmount, maxCoupons):
        """
        :type price: List[int]
        :type tastiness: List[int]
        :type maxAmount: int
        :type maxCoupons: int
        :rtype: int
        """
        dp = [[0]*(maxCoupons+1) for _ in xrange(maxAmount+1)]
        for p, t in itertools.izip(price, tastiness):
            for i in reversed(xrange(p//2, maxAmount+1)):
                for j in reversed(xrange(maxCoupons+1)):
                    if i-p >= 0:
                        dp[i][j] = max(dp[i][j], t+dp[i-p][j])
                    if j-1 >= 0:
                        dp[i][j] = max(dp[i][j], t+dp[i-p//2][j-1])
        return dp[maxAmount][maxCoupons]
